    private static final String ADMIN_COLUMNS_URL = "/v1/columns";
    private static final String PORTAL_COLUMNS_URL = "/v1/portal/columns";

    private ColumnResponse buildSampleResponse(Long id, String name, String code, boolean isSystem) {
        ColumnResponse r = new ColumnResponse();
        r.setId(id);
        r.setName(name);
        r.setCode(code);
        r.setIsSystem(isSystem);
        r.setIsVisible(true);
        r.setSortOrder(1);
        r.setCreatedAt(LocalDateTime.now());
        r.setUpdatedAt(LocalDateTime.now());
        return r;
    }

    // ============================================================
    // AC1: 栏目列表展示 — API Layer
