    @Nested
    @DisplayName("AC1: 栏目列表 API")
    class AC1_ListApi {

        @Test
        @DisplayName("4.1-INT-001: GET /v1/columns 返回全部栏目")
        void listColumns_returnsAllColumns() throws Exception {
            ColumnResponse col = buildSampleResponse(1L, "首页", "home", true);
            when(columnService.listAll()).thenReturn(List.of(col));

            mockMvc.perform(get(ADMIN_COLUMNS_URL)
                            .header(SecurityConstants.HEADER_USER_ID, "1")
                            .header(SecurityConstants.HEADER_USER_ROLE, "1"))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.code").value(200))
                    .andExpect(jsonPath("$.data").isArray())
                    .andExpect(jsonPath("$.data[0].name").value("首页"))
                    .andExpect(jsonPath("$.data[0].isSystem").value(true));
        }

        @Test
        @DisplayName("4.1-INT-002: GET /v1/columns 无权限（role=2）返回 403")
        void listColumns_noPermission_returns403() throws Exception {
            mockMvc.perform(get(ADMIN_COLUMNS_URL)
                            .header(SecurityConstants.HEADER_USER_ID, "2")
                            .header(SecurityConstants.HEADER_USER_ROLE, "2"))
                    .andExpect(status().isForbidden());
        }

        @Test
        @DisplayName("4.1-INT-003: GET /v1/columns 未认证返回 403")
        void listColumns_unauthenticated_returns403() throws Exception {
            // No headers → UserContext is null → RoleCheckAspect throws ForbiddenException
            mockMvc.perform(get(ADMIN_COLUMNS_URL))
                    .andExpect(status().isForbidden());
        }
    }

