    @Nested
    @DisplayName("Blind Spot — Flow & Data")
    class BlindSpot_FlowAndData {

        @Test
        @DisplayName("[BLIND-SPOT] 4.1-BLIND-FLOW-001: 双击提交 — 唯一性校验阻止重复")
        void create_doubleSubmit_noDuplicate() throws Exception {
            // First call succeeds, second call throws due to name uniqueness
            when(columnService.create(any()))
                    .thenReturn(1L)
                    .thenThrow(new BusinessException("栏目名称已存在"));

            String body = """
                    {"name":"测试","code":"test"}
                    """;

            mockMvc.perform(post(ADMIN_COLUMNS_URL)
                            .header(SecurityConstants.HEADER_USER_ID, "1")
                            .header(SecurityConstants.HEADER_USER_ROLE, "1")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(body))
                    .andExpect(status().isOk());

            // Simulating second submit (service would reject duplicate)
            mockMvc.perform(post(ADMIN_COLUMNS_URL)
                            .header(SecurityConstants.HEADER_USER_ID, "1")
                            .header(SecurityConstants.HEADER_USER_ROLE, "1")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(body))
                    .andExpect(status().isUnprocessableEntity());
        }

        @Test
        @DisplayName("[BLIND-SPOT] 4.1-BLIND-CONCURRENCY-002: 删除与编辑并发 — 返回 404")
        void deleteAndEdit_sameColumn_concurrent() throws Exception {
            // If column was deleted before edit, service throws ResourceNotFoundException
            doThrow(new ResourceNotFoundException("栏目", 10L))
                    .when(columnService).update(eq(10L), any());

            String body = """
                    {"name":"修改"}
                    """;

            mockMvc.perform(put(ADMIN_COLUMNS_URL + "/10")
                            .header(SecurityConstants.HEADER_USER_ID, "1")
                            .header(SecurityConstants.HEADER_USER_ROLE, "1")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(body))
                    .andExpect(status().isNotFound());
        }

        @Test
        @DisplayName("[BLIND-SPOT] 4.1-BLIND-DATA-003: 公开 API 不暴露 deleted_at/created_by 字段")
        void portalColumns_noSensitiveFields() throws Exception {
            ColumnResponse col = buildSampleResponse(1L, "首页", "home", true);
            when(columnService.listVisible()).thenReturn(List.of(col));

            mockMvc.perform(get(PORTAL_COLUMNS_URL))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.data[0].deletedAt").doesNotExist())
                    .andExpect(jsonPath("$.data[0].createdBy").doesNotExist());
        }
    }

