    @Nested
    @DisplayName("Story 4.2: 公开 API 含 subColumns")
    class Story42_PortalSubColumns {

        @Test
        @DisplayName("4.2-INT-002: GET /v1/portal/columns 仅在 sub_menu_enabled=1 时含 subColumns")
        void portalColumns_returnsSubColumnsOnlyWhenEnabled() throws Exception {
            ColumnResponse enabledCol = buildSampleResponse(3L, "政策文件", "policy", true);
            enabledCol.setSubMenuEnabled(true);
            SubColumnResponse sub = new SubColumnResponse();
            sub.setId(1L);
            sub.setColumnId(3L);
            sub.setName("国家政策");
            sub.setCode("national-policy");
            sub.setIsSystem(true);
            sub.setSortOrder(1);
            enabledCol.setSubColumns(List.of(sub));

            ColumnResponse disabledCol = buildSampleResponse(4L, "院校风采", "schools", true);
            disabledCol.setSubMenuEnabled(false);
            disabledCol.setSubColumns(Collections.emptyList());

            when(columnService.listVisible()).thenReturn(List.of(enabledCol, disabledCol));

            mockMvc.perform(get(PORTAL_COLUMNS_URL))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.data.length()").value(2))
                    .andExpect(jsonPath("$.data[0].subMenuEnabled").value(true))
                    .andExpect(jsonPath("$.data[0].subColumns").isArray())
                    .andExpect(jsonPath("$.data[0].subColumns.length()").value(1))
                    .andExpect(jsonPath("$.data[0].subColumns[0].name").value("国家政策"))
                    .andExpect(jsonPath("$.data[1].subMenuEnabled").value(false))
                    .andExpect(jsonPath("$.data[1].subColumns").isEmpty());
        }

        @Test
        @DisplayName("4.2-INT-012: GET /v1/portal/columns 无需认证，返回含 subColumns 结构")
        void portalColumns_noAuth_returnsSubColumnsStructure() throws Exception {
            ColumnResponse col = buildSampleResponse(3L, "政策文件", "policy", true);
            col.setSubMenuEnabled(true);
            col.setSubColumns(Collections.emptyList());
            when(columnService.listVisible()).thenReturn(List.of(col));

            mockMvc.perform(get(PORTAL_COLUMNS_URL))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.code").value(200))
                    .andExpect(jsonPath("$.data[0].subMenuEnabled").value(true))
                    .andExpect(jsonPath("$.data[0].subColumns").isArray());
        }
    }
